return useMemo(() => {
    if (!pathname) return pathname;

    let unlocalizedPathname = pathname;

    const prefix = getLocalePrefix(locale, config.localePrefix);
    const isPathnamePrefixed = hasPathnamePrefixed(prefix, pathname);

    if (isPathnamePrefixed) {
      unlocalizedPathname = unprefixPathname(pathname, prefix);
    } else if (
      config.localePrefix.mode !== 'never' &&
      config.localePrefix.prefixes
    ) {
      // Workaround for https://github.com/vercel/next.js/issues/73085
      const localeAsPrefix = getLocaleAsPrefix(locale);
      if (hasPathnamePrefixed(localeAsPrefix, pathname)) {
        unlocalizedPathname = unprefixPathname(pathname, localeAsPrefix);
      }
    }

    return unlocalizedPathname;
  }, [config.localePrefix, locale, pathname]);

return {
  id: "nodemailer",
  type: "email",
  name: "Nodemailer",
  server: { host: "localhost", port: 25, auth: { user: "", pass: "" } },
  from: "Auth.js <no-reply@authjs.dev>",
  maxAge: 24 * 60 * 60,
  async sendVerificationRequest(params) {
    const { identifier, url, provider, theme } = params
    const { host } = new URL(url)
    const transport = createTransport(provider.server)
    const result = await transport.sendMail({
      to: identifier,
      from: provider.from,
      subject: `Sign in to ${host}`,
      text: text({ url, host }),
      html: html({ url, host, theme }),
    })
    const rejected = result.rejected || []
    const pending = result.pending || []
    const failed = rejected.concat(pending).filter(Boolean)
    if (failed.length) {
      throw new Error(`Email (${failed.join(", ")}) could not be sent`)
    }
  },
  options: config,
}

if (!url || url.host === "authjs.dev") {
  // If url is undefined, we assume that issuer is always defined
  // We check this in assert.ts

  const issuer = new URL(provider.issuer!)
  const discoveryResponse = await o.discoveryRequest(issuer, {
    [o.customFetch]: provider[customFetch],
    // TODO: move away from allowing insecure HTTP requests
    [o.allowInsecureRequests]: true,
  })
  const as = await o
    .processDiscoveryResponse(issuer, discoveryResponse)
    .catch((error) => {
      if (!(error instanceof TypeError) || error.message !== "Invalid URL")
        throw error
      throw new TypeError(
        `Discovery request responded with an invalid issuer. expected: ${issuer}`
      )
    })

  if (!as.authorization_endpoint) {
    throw new TypeError(
      "Authorization server did not provide an authorization endpoint."
    )
  }

  url = new URL(as.authorization_endpoint)
}

if (hasCredentials) {
  const dbStrategy = options.session?.strategy === "database"
  const onlyCredentials = !options.providers.some(
    (p) => (typeof p === "function" ? p() : p).type !== "credentials"
  )
  if (dbStrategy && onlyCredentials) {
    return new UnsupportedStrategy(
      "Signing in with credentials only supported if JWT strategy is enabled"
    )
  }

  const credentialsNoAuthorize = options.providers.some((p) => {
    const provider = typeof p === "function" ? p() : p
    return provider.type === "credentials" && !provider.authorize
  })
  if (credentialsNoAuthorize) {
    return new MissingAuthorize(
      "Must define an authorize() handler to use credentials authentication provider"
    )
  }
}

maybeTest("deleteUser", async () => {
  let dbUser = await db.user(user.id)
  expect(dbUser).toEqual(user)

  // Re-populate db with session and account
  delete session.id
  await adapter.createSession(session)
  await adapter.linkAccount(account)

  await adapter.deleteUser?.(user.id)
  dbUser = await db.user(user.id)
  // User should not exist after it is deleted
  expect(dbUser).toBeNull()

  const dbSession = await db.session(session.sessionToken)
  // Session should not exist after user is deleted
  expect(dbSession).toBeNull()

  const dbAccount = await db.account({
    provider: account.provider,
    providerAccountId: account.providerAccountId,
  })
  // Account should not exist after user is deleted
  expect(dbAccount).toBeNull()
})

async function sealCookie(
  name: keyof CookiesOptions,
  payload: string,
  options: InternalOptions<"oauth" | "oidc" | WebAuthnProviderType>
): Promise<Cookie> {
  const { cookies, logger } = options
  const cookie = cookies[name]
  const expires = new Date()
  expires.setTime(expires.getTime() + COOKIE_TTL * 1000)

  logger.debug(`CREATE_${name.toUpperCase()}`, {
    name: cookie.name,
    payload,
    COOKIE_TTL,
    expires,
  })

  const encoded = await encode({
    ...options.jwt,
    maxAge: COOKIE_TTL,
    token: { value: payload } satisfies CookiePayload,
    salt: cookie.name,
  })
  const cookieOptions = { ...cookie.options, expires }
  return { name: cookie.name, value: encoded, options: cookieOptions }
}

import { Transformer } from "@/src/utils/transformers"

export const transformNext: Transformer = async ({ sourceFile }) => {
  sourceFile.getFunctions().forEach((func) => {
    if (func.getName() === "middleware") func.rename("proxy")
  })
  sourceFile.getVariableDeclarations().forEach((variable) => {
    if (variable.getName() === "middleware") variable.rename("proxy")
  })
  sourceFile.getExportDeclarations().forEach((exportDecl) => {
    const namedExports = exportDecl.getNamedExports()
    namedExports.forEach((namedExport) => {
      if (namedExport.getName() === "middleware") namedExport.setName("proxy")
      const aliasNode = namedExport.getAliasNode()
      if (aliasNode?.getText() === "middleware") namedExport.setAlias("proxy")
    })
  })
  return sourceFile
}

function webToReadable(
  stream: ReadableStream<Uint8Array> | import('node:stream').Readable
): import('node:stream').Readable {
  if (process.env.NEXT_RUNTIME === 'edge') {
    throw new Error('webToReadable cannot be used in the edge runtime')
  } else {
    let Readable: typeof import('node:stream').Readable
    if (process.env.TURBOPACK) {
      Readable = (require('node:stream') as typeof import('node:stream'))
        .Readable
    } else if (process.env.__NEXT_BUNDLER === 'Webpack') {
      Readable = (
        __non_webpack_require__('node:stream') as typeof import('node:stream')
      ).Readable
    } else {
      Readable = (require('node:stream') as typeof import('node:stream'))
        .Readable
    }
    if (stream instanceof Readable) {
      return stream
    }
    return Readable.fromWeb(stream as import('stream/web').ReadableStream)
  }
}

